// Ad-hoc test: verify MuPDF XFA parse + bind via -dbg-control TestXfa.
//
// Fixture tests/ad-hoc-xfa.pdf is generated by tests/ad-hoc-xfa.gen.py (minimal
// pure-XFA document with template + datasets packets).
//
// Run:  bun tests/ad-hoc-xfa.ts [--no-build]

import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";
import { ControlCommand, runControlCommand } from "../cmd/control.ts";
import { EXE, runStandalone } from "./util.ts";

const here = dirname(fileURLToPath(import.meta.url));

type XfaInfo = {
  has_xfa: number;
  pure_xfa: number;
  valid: number;
  page_count: number;
};

function parseXfaLine(raw: string): XfaInfo {
  const m = raw.match(/has_xfa=(\d+) pure_xfa=(\d+) valid=(\d+) page_count=(\d+)/);
  if (!m) {
    throw new Error(`unexpected TestXfa output: ${raw.trim()}`);
  }
  return {
    has_xfa: Number(m[1]),
    pure_xfa: Number(m[2]),
    valid: Number(m[3]),
    page_count: Number(m[4]),
  };
}

async function queryXfa(pdfPath: string): Promise<XfaInfo> {
  const [exitCode, raw] = await runControlCommand(EXE, ControlCommand.TestXfa, [pdfPath]);
  if (exitCode !== 0) {
    throw new Error(`TestXfa failed for ${pdfPath}: ${(raw ?? "").trim()}`);
  }
  return parseXfaLine(String(raw ?? ""));
}

export async function testit(): Promise<void> {
  const xfaPdf = join(here, "ad-hoc-xfa.pdf");
  const plainPdf = join(here, "issue-3219.pdf");

  const xfa = await queryXfa(xfaPdf);
  console.log(`ad-hoc-xfa.pdf: has_xfa=${xfa.has_xfa} pure_xfa=${xfa.pure_xfa} valid=${xfa.valid} page_count=${xfa.page_count}`);
  if (xfa.has_xfa !== 1) {
    throw new Error("ad-hoc-xfa.pdf: expected has_xfa=1");
  }
  if (xfa.pure_xfa !== 1) {
    throw new Error("ad-hoc-xfa.pdf: expected pure_xfa=1");
  }
  if (xfa.valid !== 1) {
    throw new Error(`ad-hoc-xfa.pdf: expected valid=1, got valid=${xfa.valid}`);
  }
  if (xfa.page_count !== 1) {
    throw new Error(`ad-hoc-xfa.pdf: expected page_count=1, got page_count=${xfa.page_count}`);
  }

  const plain = await queryXfa(plainPdf);
  console.log(`issue-3219.pdf: has_xfa=${plain.has_xfa} valid=${plain.valid}`);
  if (plain.has_xfa !== 0) {
    throw new Error("issue-3219.pdf: expected has_xfa=0");
  }
  if (plain.valid !== 0) {
    throw new Error("issue-3219.pdf: expected valid=0");
  }
}

if (import.meta.main) {
  await runStandalone(testit);
}